def __getattr__(name: str) -> Any:
    return getattr(parent, name)

def _shape_key(inputs: dict[str, Any]) -> tuple[int, int, int, int, int, bool]:
    return (int(inputs['B']), int(inputs['Q']), int(inputs['M']), int(inputs['D']), int(inputs['K']), bool(inputs.get('self_search', False)))

def _direct_label(inputs: dict[str, Any]) -> str | None:
    if bool(inputs.get('force_fallback', False)):
        return None
    return _DIRECT_KEYS.get(_shape_key(inputs))

def _direct_entry(label: str) -> dict[str, Any]:
    for entry in _DIRECT_ENTRIES:
        if entry['label'] == label:
            return entry
    raise KeyError(label)

def selected_route(inputs: dict[str, Any]) -> str:
    if _direct_label(inputs) is not None:
        return ROUTE_LOWD_DIRECT
    return parent.selected_route(inputs)

def selected_route_name(inputs: dict[str, Any]) -> str:
    return selected_route(inputs)

def route_info(inputs: dict[str, Any]) -> dict[str, Any]:
    label = _direct_label(inputs)
    if label is None:
        info = dict(parent.route_info(inputs))
        info['guard_order'] = [str(entry['shape_key']) for entry in SHAPE_DISPATCH_REGISTRY]
        info.setdefault('production_policy', 'weave_only')
        info.setdefault('external_fallback', None)
        return info
    entry = _direct_entry(label)
    parent_info = dict(parent.route_info(inputs))
    parent_route = str(parent_info.get('selected_route') or parent_info.get('route') or parent.selected_route(inputs))
    return {'route': ROUTE_LOWD_DIRECT, 'selected_route': ROUTE_LOWD_DIRECT, 'selected_entrypoint': entry['entrypoint'], 'parent_route': parent_route, 'replaced_route': parent_route, 'route_kind': 'specialized', 'route_source': entry['route_source'], 'coverage_class': entry['coverage_class'], 'classification': 'seed-produced', 'coverage_only': False, 'production_policy': 'weave_only', 'external_fallback': None, 'guard_order': [str(item['shape_key']) for item in SHAPE_DISPATCH_REGISTRY], 'guard_id': entry['shape_key'], 'forced_fallback': False, 'selected_guard': entry['guard'], 'fallback': parent_route, 'missing_weave_route': False, 'source_task': entry['source_task'], 'source_round_doc': entry['source_round_doc'], 'selected_seed': entry['selected_seed'], 'selected_seed_task': entry['source_task'], 'expected_seed': entry['selected_seed'], 'replaced_seed': parent_info.get('selected_seed')}

def route_trace_entry(label: str, inputs: dict[str, Any]) -> dict[str, Any]:
    return {'label': label, 'shape_key': label, 'B': int(inputs['B']), 'Q': int(inputs['Q']), 'M': int(inputs['M']), 'D': int(inputs['D']), 'K': int(inputs['K']), 'self_search': bool(inputs.get('self_search', False)), 'force_fallback': bool(inputs.get('force_fallback', False)), **route_info(inputs)}

def _compile_kernels() -> dict[str, Any]:
    return _decode_capture(_json_loads('{"d1": {"__kernel__": "dispatch_kernel_0240"}, "direct": {"__kernel__": "dispatch_kernel_0239"}}'))

def launch_parent_for_eval(inputs: dict[str, Any]) -> dict[str, Any]:
    return parent.launch_for_eval(inputs)

def launch_direct_for_eval(inputs: dict[str, Any]) -> dict[str, Any]:
    import torch
    if _direct_label(inputs) is None:
        raise ValueError('knn_search_dynamic_lowd_direct_0624_3676_v1 supports only TARGET_LABELS')
    if not _KERNELS:
        _KERNELS.update(_compile_kernels())
    bsz = int(inputs['B'])
    q_rows = int(inputs['Q'])
    if int(inputs['D']) == 1:
        _KERNELS['d1'].launch(grid=(bsz * q_rows, 1, 1), block=(THREADS, 1, 1), args=[inputs['queries'], inputs['database'], inputs['out_distances'], inputs['out_indices'], bsz, q_rows, int(inputs['M']), int(inputs['K'])], shared_mem=SMEM_POOL_BYTES)
    else:
        _KERNELS['direct'].launch(grid=(bsz * q_rows, 1, 1), block=(THREADS, 1, 1), args=[inputs['queries'], inputs['database'], inputs['out_distances'], inputs['out_indices'], bsz, q_rows, int(inputs['M']), int(inputs['K']), int(inputs['D'])], shared_mem=SMEM_POOL_BYTES)
    return {'distances': inputs['out_distances'], 'indices': inputs['out_indices']}

def launch_for_eval(inputs: dict[str, Any]) -> dict[str, Any]:
    if _direct_label(inputs) is not None:
        return launch_direct_for_eval(inputs)
    return parent.launch_for_eval(inputs)

def knn_search_compile_and_launch_dynamic_lowd_direct_3676(*, benchmark: bool=True, shapes: list[dict[str, Any]] | None=None) -> dict[str, Any]:
    from .._dispatch_runtime import evaluate
    result = evaluate(launch_for_eval, shapes=TARGET_SHAPES if shapes is None else shapes, benchmark=benchmark)
    result['passed'] = bool(result.get('summary', {}).get('all_correct'))
    print(result)
    return result
